// Solution
function validateRoutePath(path) {
  const userId = parseInt(path.split('/')[2]);
  if (isNaN(userId) || userId <= 0) {
    return path;
  } else {
    return path;
  }
}

solutions.python:
class Solution:
  def validateRoutePath(self, path: str) -> str:
    userId = path.split('/')[2]
    if not userId.isdigit() or int(userId) <= 0:
      return path
    else:
      return path
